args.sparql:
SELECT ?person ?personLabel (YEAR(?awardYear) AS ?year)
WHERE {
  ?person wdt:P166 wd:Q814815 ;
          wdt:P27 wd:Q220 .
  ?person p:P166 ?awardStatement .
  ?awardStatement ps:P166 wd:Q814815 ;
               pq:P585 ?awardYear .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en" }
}
ORDER BY ?year
LIMIT 1

